private String decrypt(String encrypted, int num) {
    String[] withEnd = encrypted.split("end~");
    int key = Integer.parseInt(withEnd[0]);
    char[] array = withEnd[0].toCharArray();
    array = Arrays.copyOfRange(array, 1, array.length);

    int[] massiv = new int[array.length];
    for (int i = 0; i < array.length; i++) {
        massiv[i] = array[i] - (key + num);
    }

    StringBuilder packet = new StringBuilder();
    for (int value : massiv) {
        packet.append((char) value);
    }

    return packet.toString() + "end~";
}
```

Note: This code assumes that the string "end~" is always present at the end of the encrypted string.

